import React from 'react';
// import { FlowChartApp } from './utils/FlowChartApp';
// import { FlowChart } from './components/FlowChart';
import { BodyWidget } from './test/components/BodyWidget';
import { Application } from './test/Application';
import './styles.css';
const [filePath, setFilePath] = useState("");
const [response, setResponse] = useState("");

const handleFilePathChange = (event) => {
setFilePath(event.target.value);
};

const handleSubmit = async (event) => {
event.preventDefault();
try {
const response = await axios.post("http://localhost:5000/process_file", { file_path: filePath }, {
headers: {
"Content-Type": "application/json"
}
});
setResponse(response.data);
} catch (error) {
setResponse({ status: "error", message: "请求失败" });
}
};


export default function App() {
var app = new Application();
return (
<div className="App">
<BodyWidget app={app} />
</div>
);
}
